const keyword = ($json.solutionInput || '').toLowerCase().trim();

// ปรับ path นี้ตาม output จริงของ HTTP_List_Solutions_SDP
const solutions = $json.solutions || $json.data || [];

const filtered = solutions.filter(s => {
  const title = (s.title || '').toLowerCase();
  const keywords = (s.keywords || '').toLowerCase();
  return title.includes(keyword) || keywords.includes(keyword);
}).slice(0, 5);

const message = filtered.length
  ? 'พบวิธีแก้ปัญหาเบื้องต้น:\n\n' +
    filtered.map((s, i) => `${i + 1}) ${s.title}\nID: ${s.id}`).join('\n\n') +
    '\n\nพิมพ์หมายเลขรายการ หรือ Solution ID'
  : 'ไม่พบวิธีแก้ปัญหาที่ตรงคำค้น กรุณาลองคำอื่น';

const payload = JSON.parse($json.payloadJson || '{}');
payload.keyword = keyword;
payload.lastResults = filtered.map((s, i) => ({
  index: i + 1,
  id: s.id,
  title: s.title
}));

return [
  {
    json: {
      ...$json,
      solutionListText: message,
      payloadJson: JSON.stringify(payload),
      currentStep: filtered.length ? 'select_solution' : 'ask_keyword',
      updatedAt: new Date().toISOString(),
      expireAt: new Date(Date.now() + 30 * 60 * 1000).toISOString()
    }
  }
];
